var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신의 은탄환은 꽤 위험했어요.","JPN":"あなたの銀の弾は相当危ないものでした。","ENG":"Your silver bullets were quite troublesome.","TWN":"你的銀彈相當危險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠시나마 정신을 잃을 만큼 잘 정제되었더군요.","JPN":"しばらく気を失ってしまうほど、よく精製されていましたね。","ENG":"Refined so well that they knocked me out for a moment.","TWN":"做得很精緻，可以讓人暫時失去意識呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만 저는 창백한 달의 저주를 받은 몸.","JPN":"でも私は青白い月の呪いを受けている身。","ENG":"But my body carries the curse of the Pale Moon.","TWN":"但是我身受蒼月的詛咒。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"양질의 피만 있다면…… 어떻게든 살아날 수 있어요.","JPN":"良質の血さえ摂取できれば……なんとかして生き返ることができます。","ENG":"As long as I have quality blood... I can always recover.","TWN":"只要有優質的血……我就能活下來。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"역시 북방합의체의 연구 기록과 일치하는군.","JPN":"やはり、北方合意体の研究記録と一致している。","ENG":"As expected, this aligns perfectly with the Northern Union's research records.","TWN":"果然與北方和議會的研究記錄一致。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"좋은 참고가 되었네.","JPN":"いい参考になった。","ENG":"A valuable reference indeed.","TWN":"很有參考價值。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"내 후원자는 창백한 달 감염자에게 더 관심이 많거든.","JPN":"私の支援者は青白い月の感染者のほうに興味を持っているんでね。","ENG":"My benefactor has quite the interest in the Pale Moon afflicted.","TWN":"我的贊助人對蒼月感染者更感興趣。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하, 뻔뻔하시군요.","JPN":"はっ、図々しいですね。","ENG":"Ha. How shameless of you.","TWN":"哈，還敢大言不慚。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"창백한 달 감염자는 찾기가 무척 어렵지.","JPN":"青白い月の感染者は珍しい。","ENG":"Finding a Pale Moon afflicted is no easy feat.","TWN":"能找到蒼月感染者非常困難。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이런 행운이 나에게 찾아오다니.","JPN":"こんな都合のいいことが私に起きるとは。","ENG":"That such a stroke of luck would come my way...","TWN":"這樣的好運竟然降臨到我身上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"그래. 어쩌면 신이 나에게 구원의 손길을 내밀어준 걸지도 모르겠어.","JPN":"そうか、もしかしたら神は私に救いの手を差し伸べてくれたのかもしれない。","ENG":"Perhaps the gods themselves have extended their hand to save me.","TWN":"或許是神向我伸出了救贖之手。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"네 말은 들리지도 않나 본데?","JPN":"聞こえてないようだけど。","ENG":"He really doesn't hear you, does he?","TWN":"你是不是聽不見我說話？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"으긋…… 입 열지 마세요.","JPN":"ううっ……黙っていてください。","ENG":"Ugh... Do not open your mouth.","TWN":"呃……別說話。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"당신 입에서 자꾸 달콤한 냄새가 나니까.","JPN":"あなたが口を開くと甘い匂いがするんです。","ENG":"Your breath reeks of something sweet.","TWN":"你說話時嘴裡總是有甜甜的味道。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아, 이런 귀중한 샘플들을 두고 내 얘기만 하고 있다니.","JPN":"ああ、貴重なサンプルを前にして、自分の話ばかりだったな。","ENG":"Ah, here I am rambling on when I have such precious samples right in front of me.","TWN":"啊，我竟然只顧著說自己的事，忽略了這些珍貴的樣本。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_SURPRISE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"당장 저들의 신병을 구속해 시험관에 집어넣도록.","JPN":"今すぐ彼女たちの身柄を拘束し、試験管に入れるように。","ENG":"Restrain them and throw them into the test chambers.","TWN":"立刻把她們抓起來，關進實驗室裡。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"누군 손 놓고 구경만 할 줄 알아?","JPN":"大人しくやられるかよ！","ENG":"You think I'm just gonna sit here and let that happen?","TWN":"你以為我會袖手旁觀嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무릎은 진작에 재생했어!","JPN":"膝はとっくに再生してるんだ！","ENG":"My knee's already healed!","TWN":"膝蓋早就再生了！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"저, 저도 가세할게요!","JPN":"わ、私も加勢します！","ENG":"I-I'll help too!","TWN":"我，我也加入作戰！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"아직 자네들을 상대할 융합체들은 많네.","JPN":"まだ君たちの相手をする融合体はたくさん残っている。","ENG":"There are still plenty of hybriders left to deal with you.","TWN":"還有很多融合體要對付你們呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"나 또한, 지친 자네들 정도는 문제없이 상대할 수 있단 말일세.","JPN":"私も、疲弊している君たちの相手をするぐらいはできる。","ENG":"And in your exhausted state, even I can handle you with ease.","TWN":"對付你們這種強弩之末的人一點問題都沒有。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Kgh...!","TWN":"呃……!"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"한가롭게 당신과 농담을 나눌 상황은 아닌 것 같네요.","JPN":"のんきに冗談を交わしてる状況ではないようですね。","ENG":"Now's hardly the time for banter.","TWN":"現在不是和你閒聊開玩笑的時候。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이런 극악무도한 짓을 벌이고도, 태평하게 대화를 나누다니…….","JPN":"こんな極悪非道なことをしておいて、平気で人と話すなんて……","ENG":"Even after committing such monstrous acts, you're standing here chatting like it's nothing...","TWN":"做出如此惡毒的事情，還能若無其事地聊天……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"KATHA_MOONLIGHT_NULL_NULL","text":{"KOREA":"제대로 미친 것 같아…….","JPN":"頭がどうかしています……","ENG":"You really are insane...","TWN":"好像真的瘋了……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KATHA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"엘릭서의 힘은 참으로 대단하군.","JPN":"エリクサーの力は実に素晴らしいな。","ENG":"The power of the Elixir is truly remarkable.","TWN":"聖水的力量真是驚人啊。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"복용자의 현실 개변력을 강제로 사용해 힘을 끌어올리다니.","JPN":"服用者の現実改変力を強制的に活性化させ、力を向上させる。","ENG":"Forcing its user to draw out his CRF like this...","TWN":"可以利用服用者的現實改變力來強行提升力量。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"엘릭서를 사용한 녀석들은 전부 끝이 안 좋았다는 거 알고 있지?","JPN":"エリクサーを使った奴らは皆、悲惨な結末を迎えたってこと、知ってるよね？","ENG":"You do know that everyone who used Elixir didn't end well, right?","TWN":"你知道那些使用聖水的傢伙都沒有好下場吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"강제로 현실 개변력을 소진한다는 게 무슨 의미인지도 알 거고.","JPN":"強制的に現実改変力を消耗することの意味もわかっているだろうし。","ENG":"You understand what it means to burn through your CRF like that.","TWN":"你會明白強制消耗現實改變力是什麼意思。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"엘릭서를 사용한 너 같은 놈들에게 주어진 건 단 하나의 선택지뿐이야.","JPN":"エリクサーを使ったあなたみたいな奴らにはたった1つしか選択肢が残されていない。","ENG":"There's only one outcome for people like you.","TWN":"像你這種使用聖水的傢伙只有一個選擇。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이대로 회복되지 않는 개변력을 모두 소진하고 침식체가 되거나.","JPN":"このまま回復しない改変力を全部使い切って侵食体になるか。","ENG":"You'll either exhaust your CRF and turn into a C.O...","TWN":"就這樣耗盡無法恢復的改變力，變成侵蝕體。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_WOLF","text":{"KOREA":"이 모든 걸 극복하고 더 우월한 종이 되는 거지.","JPN":"すべてを乗り越え、より優越な種になるか、だろう？","ENG":"Or rise above it all and become a superior being.","TWN":"克服這一切，我會成為更優越的種族。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_WOLF","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};